const items = $input.all();

// Розумний хелпер для динамічного пошуку колонок за першими літерами
const getValByPrefix = (row, prefix) => {
  const key = Object.keys(row).find(k => k.toLowerCase().trim().startsWith(prefix.toLowerCase()));
  return key ? row[key] : '';
};

// Динамічний класифікатор типів
const parsePropertyType = (url, title, desc) => {
  const text = `${url} ${title} ${desc}`.toLowerCase();

  if (text.includes('vila') || text.includes('villa') || text.includes('shtepi') || text.includes('house') || text.includes('будинок') || text.includes('вілла')) {
    return 'Villa';
  }
  if (text.includes('truall') || text.includes('toke') || text.includes('land') || text.includes('plot') || text.includes('ділянка')) {
    return 'Land';
  }
  if (text.includes('ambient') || text.includes('biznes') || text.includes('commercial') || text.includes('office') || text.includes('комерційн') || text.includes('офіс') || text.includes('magazin') || text.includes('dyqan')) {
    return 'Commercial';
  }
  return 'Apartment';
};

// Визначення локації
const parseLocation = (url, title, desc) => {
  const text = `${url} ${title} ${desc}`.toLowerCase();

  let city = 'Durrës';
  if (text.includes('tirane') || text.includes('tirana') || text.includes('bllok') || text.includes('lake park')) {
    city = 'Tirana';
  }

  let district = 'Plazh';
  if (city === 'Tirana') {
    district = 'Center';
    if (text.includes('bllok')) district = 'Blloku';
    else if (text.includes('lake') || text.includes('liqen')) district = 'Lake Park';
    else if (text.includes('don bosko')) district = 'Don Bosko';
  } else {
    if (text.includes('golem')) district = 'Golem';
    else if (text.includes('qerret')) district = 'Qerret';
    else if (text.includes('vollga')) district = 'Vollga';
    else if (text.includes('mali i robit')) district = 'Mali i Robit';
    else if (text.includes('hamallaj')) district = 'Hamallaj';
    else if (text.includes('lalz')) district = 'Gjiri i Lalzit';
    else if (text.includes('shkembi') || text.includes('kavaj')) district = 'Shkëmbi i Kavajës';
  }

  return { city, district };
};

const formatted = items.map(item => {
  const row = item.json;
  const url = getValByPrefix(row, 'url');
  const title = getValByPrefix(row, 'title');
  const desc = getValByPrefix(row, 'description');
  const price = getValByPrefix(row, 'price') || '0 €';
  const categoryRaw = getValByPrefix(row, 'category');

  const loc = parseLocation(url, title, desc);
  const type = parsePropertyType(url, title, desc);

  // Нормалізація категорії
  const category = categoryRaw.toLowerCase().includes('rent') || categoryRaw.toLowerCase().includes('оренда') ? 'Rent' : 'Sale';

  return {
    url,
    title,
    price,
    category,
    area: getValByPrefix(row, 'area') || '0 m2',
    bedrooms: getValByPrefix(row, 'bedrooms') || '0',
    description: desc,
    agentName: getValByPrefix(row, 'agent name') || 'Century 21',
    agentPhone: getValByPrefix(row, 'agent phone'),
    lastModified: getValByPrefix(row, 'last modified') || new Date().toISOString(),
    image: getValByPrefix(row, 'image') || 'https://images.unsplash.com/photo-1560448204-e02f11c3d0e2?auto=format&fit=crop&w=400&q=80',
    city: loc.city,
    district: loc.district,
    type: type
  };
});

return formatted;
